#!/usr/bin/env bash# scripts/hermes/sync-context.sh — Sync Layer 2: Hermes Context (no secrets)# Usage: bash scripts/hermes/sync-context.sh [--push|--pull]set -euo pipefailREPO_ROOT="$(cd "$(dirname "${BASH_SOURCE[0]}")/../.." && pwd)"HERMES_DIR="$REPO_ROOT/scripts/hermes/.hermes"MODE="${1:---pull}"if [ "$MODE" = "--push" ]; then  echo "?? Pushing Hermes context to GitHub..."  cd "$REPO_ROOT"  git add scripts/hermes/.hermes/config.yaml  git add scripts/hermes/.hermes/SOUL.md  git add scripts/hermes/.hermes/memory/  git add scripts/hermes/.hermes/hermes-agent/sessions/  if git diff --cached --quiet; then    echo "? No changes to push"  else    git commit -m "chore(hermes): sync context [auto]"    git push origin main    echo "? Hermes context pushed to GitHub"  fielse  echo "?? Pulling Hermes context from GitHub..."  cd "$REPO_ROOT"  git pull origin main --rebase  echo "? Hermes context pulled from GitHub"fi